chats.customCss:
/* ========== 基础隐藏 ========== */
div.folder-tab {
 visibility: hidden !important;
}
div.folder-tab > * {
 visibility: visible !important;
}

div.folder-curve-connector {
 display: none !important;
}

/* ========== 顶栏区域 ========== */
.folder-header-container {
 position: fixed !important;
 top: 0 !important;
 left: 0 !important;
 right: 0 !important;
 z-index: 9999 !important;
 background-image: url('https://i.postimg.cc/1RFpw8nD/wu-biao-ti91-20260308051747.png') !important;
 background-size: cover !important;
 background-position: center !important;
 border-top-left-radius: 0 !important;
 border-top-right-radius: 0 !important;
 padding-top: calc(15px + var(--safe-top, 0px)) !important;
 padding-bottom: 21px !important;
 min-height: auto !important;
}

.room-header {
 height: auto !important;
 min-height: 50px !important;
 display: flex !important;
 align-items: center !important;
 justify-content: center !important;
}

/* 返回键图标 */
div.folder-back-btn {
 background-image: url('https://i.postimg.cc/qR2PRgQ9/wu-biao-ti81-20260214171310.png') !important;
 background-size: 30px 30px !important;
 background-position: center !important;
 background-repeat: no-repeat !important;
 font-size: 0 !important;
 color: transparent !important;
 width: 24px !important;
 height: 24px !important;
 background-color: transparent !important;
 position: relative !important;
 top: 24px !important;
 left: -7px !important;
}

/* 返回键右边添加"消息"文字 */
div.folder-back-btn::after {
 content: "消息" !important;
 position: absolute !important;
 left: 24px !important;
 top: 54% !important;
 transform: translateY(-50%) !important;
 color: #000 !important;
 font-size: 16px !important;
 font-weight: normal !important;
 white-space: nowrap !important;
 z-index: 1 !important;
}

/* 备注名 */
div.folder-back-btn + * {
 color: #000 !important;
 position: relative !important;
 top: 15px !important;
 left: 138px !important;
 font-size: 16px !important;
 margin-bottom: 0 !important;
 line-height: 1.2 !important;
}

/* 备注下面添加"1分钟前在线" */
div.folder-back-btn + *::after {
 content: "1分钟前在线" !important;
 position: absolute !important;
 left: -15px !important;
 top: 20px !important;
 color: #8F8F91 !important;
 font-size: 12px !important;
 font-weight: normal !important;
 white-space: nowrap !important;
 z-index: 1 !important;
}

/* 右侧三个点操作按钮 */
i.fas.fa-bars {
 background-image: url('https://i.postimg.cc/gJ87dDWH/IMG-6070.jpg') !important;
 background-size: cover !important;
 background-position: center !important;
 background-repeat: no-repeat !important;
 font-size: 0 !important;
 color: transparent !important;
 width: 35px !important;
 min-width: 35px !important;
 max-width: 35px !important;
 height: 35px !important;
 min-height: 35px !important;
 max-height: 35px !important;
 border-radius: 999px !important;
 overflow: hidden !important;
 box-sizing: border-box !important;
 position: static !important;
 background-color: transparent !important;
 margin-top: 52px !important;
}

/* 右上角按钮透明化 */
.folder-menu-btn,
.folder-menu-btn * {
 background: transparent !important;
 border: none !important;
 box-shadow: none !important;
 outline: none !important;
 color: transparent !important;
}

/* 心声按钮 */
div[class*="invisible-heart"] {
   background-image: none !important;
   width: 40px !important;
   height: 40px !important;
   background-color: transparent !important;
   position: relative !important;
   top: 41px !important;
   left: -5px !important;
   opacity: 0 !important;
   pointer-events: auto !important;
   z-index
}

/* 多选模式修复 */
.multi-select-navbar {
 z-index: 10000 !important;
 padding-top: calc(15px + var(--safe-top, 0px)) !important;
}
.chat-room.multi-select-mode .folder-header-container {
 display: none !important;
}
.chat-room.multi-select-mode .room-content {
 padding-top: 50px !important;
}

/* ========== 聊天内容区域 ========== */
.room-content {
 padding-top: calc(-30px + var(--safe-top, 0px)) !important;
 background: transparent !important;
 background-image: none !important;
}

/* 确保父容器不遮挡壁纸 */
.chat-container {
 background: transparent !important;
}

/* 圆形头像 */
.Miu-miu .avatar-img {
 border-radius: 50% !important;
 width: 38px !important;
 height: 38px !important;
 object-fit: cover !important;
}

/* 确保最后一条消息没有额外边距 */
.Miu-miu:last-child {
 margin-bottom: 5px !important;
 padding-bottom: 0 !important;
}

/* 移除聊天内容区域的底部内边距 */
.room-content {
 padding-bottom: 0 !important;
}

/* ========== 普通文本气泡 ========== */
.Miu-miu.user .content {
 background: #000000 !important;
 color: #FFF !important;
 position: relative !important;
 padding-right: 40px !important;
}
.Miu-miu.ai .content {
 background: #ffffff !important;
 color: #333 !important;
 position: relative !important;
 padding-right: 36px !important;
}

/* ========== 小尾巴 ========== */
.Miu-miu.user .content::after,
.Miu-miu.ai .content::before {
 display: none !important;
}

/* 用户最后一条消息的尾巴 */
.Miu-miu.user:not(:has(+ .Miu-miu.user)) .content::after {
 display: block !important;
 background-color: #000 !important;
 bottom: -15px !important;
 content: '' !important;
 position: absolute !important;
}

/* AI最后一条消息的尾巴 */
.Miu-miu.ai:not(:has(+ .Miu-miu.ai)) .content::before {
 display: block !important;
 background-color: #fff !important;
 bottom: -13px !important;
 left: -7px !important;
 content: '' !important;
 position: absolute !important;
}

/* ========== 用户气泡内部图案和时间戳 ========== */
.Miu-miu.user .content {
 position: relative !important;
 padding-right: 53px !important;
}

/* 用户气泡内部右侧小图案 */
.Miu-miu.user .content::before {
 content: "" !important;
 position: absolute !important;
 right: 10px !important;
 bottom: 6px !important;
 width: 12px !important;
 height: 12px !important;
 background-image: url("https://file.ljcdn.com/psd-sinan-file/prod/appeal_evidence/A8FD80A8C7C5471FB816B4D10532D05C/qdqqd.png") !important;
 background-size: contain !important;
 background-repeat: no-repeat !important;
 background-position: center !important;
 z-index: 10 !important;
}

/* 时间戳通用样式 */
.time {
 position: absolute !important;
 right: 8px !important;
 bottom: 8px !important;
 color: #999 !important;
 margin: 0 !important;
 padding: 0 !important;
 line-height: 1 !important;
 z-index: 999 !important;
 transform: scale(0.88) !important;
 transform-origin: right bottom !important;
}

/* 用户气泡时间戳位置（在图案左边） */
.Miu-miu.user .time {
 position: absolute !important;
 right: 25px !important;
 bottom: 8px !important;
 color: #A4A3A5 !important;
}

/* AI气泡时间戳颜色 */
.Miu-miu.ai .time {
 color: #989898 !important;
}

/* ========== 语音气泡 ========== */
/* AI语音气泡 */
.Miu-miu.ai .content.voice-bubble {
 min-width: 200px !important;
 padding: 20px 16px !important;
 border-radius: 18px !important;
 background-color: #ffffff !important;
 background-image: url('https://i.postimg.cc/wxC1ZrsX/wu-biao-ti83-20260214170830.png') !important;
 background-repeat: no-repeat !important;
 background-position: left -6px !important;
 background-size: 65px 65px !important;
}
.Miu-miu.ai:nth-of-type(n+2) .content.voice-bubble {
 border-bottom-left-radius: 8px !important;
}
.Miu-miu.ai .content.voice-bubble .voice-icon,
.Miu-miu.ai .content.voice-bubble .voice-duration {
 color: #666 !important;
}

/* 用户语音气泡 */
.Miu-miu.user .content.voice-bubble {
 min-width: 200px !important;
 padding: 20px 16px !important;
 border-radius: 18px !important;
 background-image: url('https://i.postimg.cc/7Zsw8CQS/wu-biao-ti83-20260214171159.png') !important;
 background-repeat: no-repeat !important;
 background-position: left -6px !important;
 background-size: 65px 65px !important;
}
.Miu-miu.user:nth-of-type(n+2) .content.voice-bubble {
 border-bottom-right-radius: 8px !important;
}
.Miu-miu.user .content.voice-bubble .voice-icon,
.Miu-miu.user .content.voice-bubble .voice-duration {
 color: #FFF !important;
}

/* ========== 气泡形状规则 ========== */
/* 基础圆角 */
.Miu-miu.user .content,
.Miu-miu.ai .content {
 border-radius: 20px !important;
}

/* 用户气泡右上角 - 连续消息 */
.Miu-miu.user + .Miu-miu.user .content {
 border-top-right-radius: 10px !important;
}
.Miu-miu.user:has(+ .Miu-miu.user .content.voice-bubble) + .Miu-miu.user .content,
.Miu-miu.user:has(+ .Miu-miu.user .image-bubble) + .Miu-miu.user .content {
 border-top-right-radius: 20px !important;
}

/* 用户气泡右下角 - 连续消息 */
.Miu-miu.user:has(+ .Miu-miu.user) .content {
 border-bottom-right-radius: 10px !important;
}
.Miu-miu.user:has(+ .Miu-miu.user .content.voice-bubble) .content,
.Miu-miu.user:has(+ .Miu-miu.user .image-bubble) .content {
 border-bottom-right-radius: 20px !important;
}

/* AI气泡左上角 - 连续消息 */
.Miu-miu.ai + .Miu-miu.ai .content {
 border-top-left-radius: 10px !important;
}
.Miu-miu.ai:has(+ .Miu-miu.ai .content.voice-bubble) + .Miu-miu.ai .content,
.Miu-miu.ai:has(+ .Miu-miu.ai .image-bubble) + .Miu-miu.ai .content {
 border-top-left-radius: 20px !important;
}

/* AI气泡左下角 - 连续消息 */
.Miu-miu.ai:has(+ .Miu-miu.ai) .content {
 border-bottom-left-radius: 10px !important;
}
.Miu-miu.ai:has(+ .Miu-miu.ai .content.voice-bubble) .content,
.Miu-miu.ai:has(+ .Miu-miu.ai .image-bubble) .content {
 border-bottom-left-radius: 20px !important;
}

/* 特殊气泡全圆角 */
.Miu-miu.user .content.voice-bubble,
.Miu-miu.ai .content.voice-bubble,
.image-bubble,
.pv-card,
.transfer-card,
.gift-card,
.custom-emotion {
 border-radius: 20px !important;
}

/* ========== 连续消息间距 ========== */
.Miu-miu.user + .Miu-miu.user,
.Miu-miu.user + .Miu-miu.user + .Miu-miu.user,
.Miu-miu.user + .Miu-miu.user + .Miu-miu.user + .Miu-miu.user,
.Miu-miu.ai + .Miu-miu.ai,
.Miu-miu.ai + .Miu-miu.ai + .Miu-miu.ai {
 margin-top: -3px !important;
}
.Miu-miu.user + .Miu-miu.ai,
.Miu-miu.ai + .Miu-miu.user {
 margin-top: 10px !important;
}

/* ========== 引用回复消息 ========== */
.Miu-miu .content {
 display: inline-flex !important;
 flex-direction: column !important;
}
.reply-tiny-bubble {
 order: -1 !important;
 margin-top: 0 !important;
 margin-bottom: 4px !important;
}
.Miu-miu.ai .content .reply-tiny-bubble {
 align-self: flex-start !important;
}
.Miu-miu.user .content .reply-tiny-bubble {
 align-self: flex-end !important;
}

.reply-tiny-bubble {
 margin-bottom: 6px !important;
 padding: 6px 10px 6px 12px !important;
 background-color: rgba(250,250,250,0.6) !important;
 border-radius: 9px !important;
 position: relative !important;
 display: inline-flex !important;
 flex-direction: column !important;
 width: auto !important;
 min-width: fit-content !important;
 max-width: 85% !important;
 white-space: normal !important;
 overflow: visible !important;
 box-sizing: border-box !important;
 cursor: pointer !important;
 border: 0.55px solid rgba(0, 0, 0, 0.08) !important;
 border-left: none !important;
}
.Miu-miu.ai .reply-tiny-bubble {
 display: inline-flex !important;
 width: auto !important;
 white-space: normal !important;
}
.reply-tiny-bubble::before {
 content: '' !important;
 position: absolute !important;
 left: 7px !important;
 top: 50% !important;
 transform: translateY(-50%) !important;
 width: 2px !important;
 height: 30px !important;
 background-color: #000 !important;
 border-radius: 1px !important;
 z-index: 2 !important;
}
.reply-tiny-bubble > :first-child {
 font-size: 10.5px !important;
 font-weight: 600 !important;
 color: #000 !important;
 margin-bottom: 2px !important;
 display: block !important;
 white-space: nowrap !important;
 overflow: hidden !important;
 text-overflow: ellipsis !important;
 max-width: 100% !important;
 padding-left: 2px !important;
}
.reply-tiny-bubble > :nth-child(2) {
 font-size: 14px !important;
 color: #666 !important;
 line-height: 1.4 !important;
 display: block !important;
 white-space: normal !important;
 overflow: visible !important;
 max-width: 100% !important;
 padding-left: 2px !important;
}
.reply-tiny-bubble > :nth-child(3) {
 font-size: 11px !important;
 color: #999 !important;
 position: absolute !important;
 top: 6px !important;
 right: 10px !important;
}
.user .reply-tiny-bubble::before {
 background-color: #000 !important;
}
.user .reply-tiny-bubble > :first-child {
 color: #000 !important;
}
.reply-tiny-bubble:hover {
 background-color: rgba(0, 0, 0, 0.04) !important;
 border-color: rgba(0, 0, 0, 0.12) !important;
}
.reply-tiny-bubble * {
 margin: 0 !important;
 padding: 0 !important;
}
.reply-tiny-bubble:not(:empty)::before {
 display: block !important;
 visibility: visible !important;
 opacity: 1 !important;
}
.reply-tiny-bubble .content.photo-only,
.reply-tiny-bubble .content.sticker-only,
.reply-tiny-bubble .content.voice-bubble {
 max-width: 50px !important;
 max-height: 50px !important;
 border-radius: 4px !important;
 overflow: hidden !important;
}
.reply-tiny-bubble img {
 max-width: 50px !important;
 max-height: 50px !important;
 border-radius: 4px !important;
 object-fit: cover !important;
}
.reply-tiny-bubble .content.transfer-msg {
 padding: 4px 6px !important;
 background-color: rgba(255, 255, 255, 0.9) !important;
 border-radius: 4px !important;
 font-size: 11px !important;
 display: flex !important;
 align-items: center !important;
 gap: 4px !important;
 max-width: 150px !important;
 white-space: nowrap !important;
 overflow: hidden !important;
 text-overflow: ellipsis !important;
}
.reply-tiny-bubble .content.voice-bubble {
 background-color: rgba(255, 255, 255, 0.9) !important;
 padding: 4px 8px !important;
 border-radius: 12px !important;
 display: inline-flex !important;
 align-items: center !important;
 gap: 4px !important;
 font-size: 12px !important;
}

/* ========== 图片/相册/转账消息时间戳隐藏 ========== */
.Miu-miu:has(.content.photo-only) .time,
.Miu-miu:has(.content.album-only) .time,
.Miu-miu:has(.content.sticker-only) .time,
.Miu-miu:has(.content.transfer-msg) .time,
.Miu-miu .content.photo-only .time,
.Miu-miu .content.album-only .time,
.Miu-miu .content.sticker-only .time,
.Miu-miu .content.transfer-msg .time,
.Miu-miu .content.photo-only ~ .time,
.Miu-miu .content.album-only ~ .time,
.Miu-miu .content.sticker-only ~ .time,
.Miu-miu .content.transfer-msg ~ .time {
 display: none !important;
 visibility: hidden !important;
 opacity: 0 !important;
 position: absolute !important;
 z-index: -999 !important;
 width: 0 !important;
 height: 0 !important;
 margin: 0 !important;
 padding: 0 !important;
}
.Miu-miu:has(.content.photo-only) .content,
.Miu-miu:has(.content.album-only) .content,
.Miu-miu:has(.content.sticker-only) .content,
.Miu-miu:has(.content.transfer-msg) .content,
.Miu-miu .content.photo-only,
.Miu-miu .content.album-only,
.Miu-miu .content.sticker-only,
.Miu-miu .content.transfer-msg {
 padding-right: 11px !important;
 padding-left: 11px !important;
 margin: 0 !important;
}

/* ========== 图片/相册消息无气泡 ========== */
.Miu-miu .content.photo-only,
.Miu-miu .content.album-only,
.Miu-miu.ai + .Miu-miu.ai .content.photo-only,
.Miu-miu.ai + .Miu-miu.ai .content.album-only,
.Miu-miu.user + .Miu-miu.user .content.photo-only,
.Miu-miu.user + .Miu-miu.user .content.album-only {
 padding: 0 !important;
 background: transparent !important;
 border: none !important;
 border-radius: 0 !important;
 box-shadow: none !important;
 margin: 0 !important;
 width: auto !important;
 max-width: none !important;
}

/* ========== 图片/相册消息隐藏小尾巴 ========== */
.Miu-miu .content.photo-only::before,
.Miu-miu .content.photo-only::after,
.Miu-miu .content.album-only::before,
.Miu-miu .content.album-only::after,
.Miu-miu.ai + .Miu-miu.ai .content.photo-only::before,
.Miu-miu.ai + .Miu-miu.ai .content.photo-only::after,
.Miu-miu.ai + .Miu-miu.ai .content.album-only::before,
.Miu-miu.ai + .Miu-miu.ai .content.album-only::after,
.Miu-miu.user + .Miu-miu.user .content.photo-only::before,
.Miu-miu.user + .Miu-miu.user .content.photo-only::after,
.Miu-miu.user + .Miu-miu.user .content.album-only::before,
.Miu-miu.user + .Miu-miu.user .content.album-only::after {
 display: none !important;
 content: none !important;
}

/* ========== 图片消息强制隐藏小尾巴 ========== */
.Miu-miu.ai .content.photo-only::before,
.Miu-miu.user .content.photo-only::after,
.Miu-miu.ai + .Miu-miu.ai .content.photo-only::before,
.Miu-miu.user + .Miu-miu.user .content.photo-only::after {
 display: none !important;
 content: none !important;
 opacity: 0 !important;
 visibility: hidden !important;
 width: 0 !important;
 height: 0 !important;
}

/* ===== 终极强制：所有图片消息隐藏小尾巴 ===== */
.Miu-miu .content.photo-only::after,
.Miu-miu .content.photo-only::before,
.Miu-miu .content.album-only::after,
.Miu-miu .content.album-only::before {
 display: none !important !important;
 content: none !important !important;
 opacity: 0 !important;
 visibility: hidden !important;
 width: 0 !important;
 height: 0 !important;
 position: absolute !important;
 z-index: -9999 !important;
}

/* ========== 转账消息无气泡 ========== */
.Miu-miu .content.transfer-msg,
.Miu-miu.ai .content.transfer-msg,
.Miu-miu.user .content.transfer-msg,
.Miu-miu.ai + .Miu-miu.ai .content.transfer-msg,
.Miu-miu.user + .Miu-miu.user .content.transfer-msg {
 padding: 0 !important;
 background: transparent !important;
 background-color: transparent !important;
 border: none !important;
 border-radius: 0 !important;
 box-shadow: none !important;
 width: auto !important;
 max-width: none !important;
}

/* ========== 转账卡片样式 ========== */
.transfer-card,
.transfer-card.done,
.transfer-card.refund,
.transfer-card.received,
.transfer-card.couple-card,
.transfer-card.relative-card {
 border: none !important;
 box-shadow: none !important;
 background: transparent !important;
 background-color: transparent !important;
}

/* ========== 转账消息隐藏小尾巴 ========== */
.Miu-miu.ai .content.transfer-msg::before,
.Miu-miu.user .content.transfer-msg::after,
.Miu-miu.ai + .Miu-miu.ai .content.transfer-msg::before,
.Miu-miu.user + .Miu-miu.user .content.transfer-msg::after {
 display: none !important;
 content: none !important;
 opacity: 0 !important;
 visibility: hidden !important;
 width: 0 !important;
 height: 0 !important;
}

/* ========== 转账卡片隐藏小尾巴 ========== */
.transfer-card::after,
.bubble-wrapper.transfer-wrapper .transfer-card::after,
.Miu-miu.ai .transfer-card::after {
 display: none !important;
 content: none !important;
}

/* ========== 所有表情包消息完全隐藏小尾巴 ========== */
.Miu-miu .content.sticker-only::before,
.Miu-miu .content.sticker-only::after {
 display: none !important;
 content: none !important;
}

/* ========== 底栏区域 ========== */
.room-footer {
 background: #F7F7F7 !important;
 clip-path: inset(6px 0 0 0) !important;
 position: relative !important;
}

/* 底部按钮 */
.footer-btn-side {
 background: transparent !important;
 border: none !important;
 box-shadow: none !important;
 position: relative !important;
}
.footer-btn-side::before {
 content: "" !important;
 position: absolute !important;
 left: -8px !important;
 top: 0 !important;
 width: 100% !important;
 height: 100% !important;
 background-image: url("https://xiaoiwg.dongfeng-nissan.com.cn/aicc-workbench/res/download/default/temp/images/20260213/8b2709993e6469fbcb5077b86877c71815d73921.png") !important;
 background-size: 35px 35px !important;
 background-repeat: no-repeat !important;
 background-position: center !important;
 z-index: 1 !important;
}
.footer-btn-side * {
 opacity: 0 !important;
 visibility: hidden !important;
}

/* 右侧发送按钮 */
.room-footer .footer-btn-side:last-child {
 background: transparent !important;
 border: none !important;
 box-shadow: none !important;
 position: relative !important;
}
.room-footer .footer-btn-side:last-child::before {
 content: "" !important;
 position: absolute !important;
 left: 0 !important;
 top: 0 !important;
 width: 100% !important;
 height: 100% !important;
