}
.Miu-miu.ai .reply-tiny-bubble {
 display: inline-flex !important;
 width: auto !important;
 white-space: normal !important;
}
.reply-tiny-bubble::before {
 content: '' !important;
 position: absolute !important;
 left: 7px !important;
 top: 50% !important;
 transform: translateY(-50%) !important;
