.Miu-miu:has(.content.album-only) .time,
.Miu-miu:has(.content.sticker-only) .time,
.Miu-miu:has(.content.transfer-msg) .time,
.Miu-miu .content.photo-only .time,
.Miu-miu .content.album-only .time,
.Miu-miu .content.sticker-only .time,
